  1	import * as React from 'react';
  2	import { Dropdown, DropdownList, MenuToggle, MenuToggleElement, TooltipPosition } from '@patternfly/react-core';
  3	import { WorkloadOverview } from '../../types/ServiceInfo';
  4	import {
  5	  DestinationRule,
  6	  DestinationRuleC,
  7	  getWizardUpdateLabel,
  8	  K8sGRPCRoute,
  9	  K8sHTTPRoute,
 10	  PeerAuthentication,
 11	  VirtualService
 12	} from '../../types/IstioObjects';
 13	import * as AlertUtils from '../../utils/AlertUtils';
 14	import { serverConfig } from '../../config';
 15	import { TLSStatus } from '../../types/TLSStatus';
 16	import * as API from '../../services/Api';
 17	import {
 18	  buildAnnotationPatch,
 19	  WIZARD_REQUEST_ROUTING,
 20	  WIZARD_FAULT_INJECTION,
 21	  WIZARD_TRAFFIC_SHIFTING,
 22	  WIZARD_REQUEST_TIMEOUTS,
 23	  WIZARD_TCP_TRAFFIC_SHIFTING,
 24	  WIZARD_K8S_REQUEST_ROUTING,
 25	  WIZARD_K8S_GRPC_REQUEST_ROUTING,
 26	  WIZARD_EDIT_ANNOTATIONS
 27	} from './WizardActions';
 28	import { MessageType } from '../../types/MessageCenter';
 29	import { WizardLabels } from './WizardLabels';
 30	import { ServiceWizard } from './ServiceWizard';
 31	import { canCreate, canUpdate, ResourcePermissions } from '../../types/Permissions';
 32	import { ServiceWizardActionsDropdownGroup, DELETE_TRAFFIC_ROUTING } from './ServiceWizardActionsDropdownGroup';
 33	import { ConfirmDeleteTrafficRoutingModal } from './ConfirmDeleteTrafficRoutingModal';
 34	import { deleteServiceTrafficRouting } from 'services/Api';
 35	import { ServiceOverview } from '../../types/ServiceList';
 36	import { KialiAppState } from '../../store/Store';
 37	import { connect } from 'react-redux';
 38	import { renderDisabledDropdownOption } from 'utils/DropdownUtils';
 39	import { t } from 'utils/I18nUtils';
 40	import { getAppLabelName, getVersionLabelName } from 'config/ServerConfig';
 41	
 42	type ReduxProps = {
 43	  istioAPIEnabled: boolean;
 44	};
 45	
 46	type Props = ReduxProps & {
 47	  annotations: { [key: string]: string };
 48	  cluster?: string;
 49	  destinationRules: DestinationRule[];
 50	  gateways: string[];
 51	  istioPermissions: ResourcePermissions;
 52	  k8sGRPCRoutes: K8sGRPCRoute[];
 53	  k8sGateways: string[];
 54	  k8sHTTPRoutes: K8sHTTPRoute[];
 55	  namespace: string;
 56	  onChange: () => void;
 57	  peerAuthentications: PeerAuthentication[];
 58	  readOnly: boolean;
 59	  serviceName: string;
 60	  show: boolean;
 61	  subServices: ServiceOverview[];
 62	  tlsStatus?: TLSStatus;
 63	  virtualServices: VirtualService[];
 64	  workloads: WorkloadOverview[];
 65	};
 66	
 67	const ServiceWizardDropdownComponent: React.FC<Props> = (props: Props) => {
 68	  const [isDeleting, setIsDeleting] = React.useState<boolean>(false);
 69	  const [isActionsOpen, setIsActionsOpen] = React.useState<boolean>(false);
 70	  const [showAnnotationsWizard, setShowAnnotationsWizard] = React.useState<boolean>(false);
 71	  const [showConfirmDelete, setShowConfirmDelete] = React.useState<boolean>(false);
 72	  const [showWizard, setShowWizard] = React.useState<boolean>(props.show);
 73	  const [updateWizard, setUpdateWizard] = React.useState<boolean>(false);
 74	  const [wizardType, setWizardType] = React.useState<string>('');
 75	
 76	  const checkHasMeshWorkloads = (): boolean => {
 77	    let hasMeshWorkloads = false;
 78	    for (let i = 0; i < props.workloads.length; i++) {
 79	      if (props.workloads[i].istioSidecar) {
 80	        // At least one workload with sidecar
 81	        hasMeshWorkloads = true;
 82	        break;
 83	      }
 84	      // Check for Ambient if in Ambient Mesh
 85	      if (serverConfig.ambientEnabled && props.workloads[i].isAmbient) {
 86	        hasMeshWorkloads = true;
 87	        break;
 88	      }
 89	    }
 90	    return hasMeshWorkloads;
 91	  };
 92	
 93	  const hideConfirmDelete = (): void => {
 94	    setShowConfirmDelete(false);
 95	  };
 96	
 97	  const getValidWorkloads = (): WorkloadOverview[] => {
 98	    return props.workloads.filter(workload => {
 99	      // A workload could skip the version label on this check only when there is a single workload list
100	      const appLabelName = getAppLabelName(workload.labels);
101	      const verLabelName = getVersionLabelName(workload.labels);
102	      return workload.labels && appLabelName && (verLabelName || props.workloads.length === 1);
103	    });
104	  };
105	
106	  const onAction = (key: string): void => {
107	    const updateLabel = getWizardUpdateLabel(props.virtualServices, props.k8sHTTPRoutes, props.k8sGRPCRoutes);
108	
109	    switch (key) {
110	      case WIZARD_REQUEST_ROUTING:
111	      case WIZARD_FAULT_INJECTION:
112	      case WIZARD_TRAFFIC_SHIFTING:
113	      case WIZARD_TCP_TRAFFIC_SHIFTING:
114	      case WIZARD_K8S_REQUEST_ROUTING:
115	      case WIZARD_K8S_GRPC_REQUEST_ROUTING:
116	      case WIZARD_REQUEST_TIMEOUTS: {
117	        setShowWizard(true);
118	        setWizardType(key);
119	        setUpdateWizard(key === updateLabel);
120	        break;
121	      }
122	      case DELETE_TRAFFIC_ROUTING: {
123	        setShowConfirmDelete(true);
124	        break;
125	      }
126	      case WIZARD_EDIT_ANNOTATIONS: {
127	        setShowAnnotationsWizard(true);
128	        break;
129	      }
130	      default:
131	        console.log('Unrecognized key');
132	    }
133	  };
134	
135	  const onActionsSelect = (_event?: React.MouseEvent<Element, MouseEvent>): void => {
136	    setIsActionsOpen(!isActionsOpen);
137	  };
138	
139	  const onActionsToggle = (isOpen: boolean): void => {
140	    setIsActionsOpen(isOpen);
141	  };
142	
143	  const onClose = (changed: boolean): void => {
144	    setShowWizard(false);
145	    if (changed) {
146	      props.onChange();
147	    }
148	  };
149	
150	  const onDelete = (): void => {
151	    setIsDeleting(true);
152	    hideConfirmDelete();
153	
154	    deleteServiceTrafficRouting(
155	      props.virtualServices,
156	      DestinationRuleC.fromDrArray(props.destinationRules),
157	      props.k8sHTTPRoutes,
158	      props.k8sGRPCRoutes,
159	      props.cluster
160	    )
161	      .then(_results => {
162	        AlertUtils.addSuccess(`Istio Config deleted for ${props.serviceName} service.`);
163	
164	        setIsDeleting(false);
165	        props.onChange();
166	      })
167	      .catch(error => {
168	        AlertUtils.addError('Could not delete Istio config objects.', error);
169	
170	        setIsDeleting(false);
171	      });
172	  };
173	
174	  const onChangeAnnotations = (annotations: { [key: string]: string }): void => {
175	    const jsonInjectionPatch = buildAnnotationPatch(annotations);
176	
177	    API.updateService(props.namespace, props.serviceName, jsonInjectionPatch, 'json', props.cluster)
178	      .then(_ => {
179	        AlertUtils.add(`Service ${props.serviceName} updated`, 'default', MessageType.SUCCESS);
180	      })
181	      .catch(error => {
182	        AlertUtils.addError(`Could not update service ${props.serviceName}`, error);
183	      })
184	      .finally(() => {
185	        setShowAnnotationsWizard(false);
186	        props.onChange();
187	      });
188	  };
189	
190	  const hasMeshWorkloads = checkHasMeshWorkloads();
191	  const toolTipMsgActions = !hasMeshWorkloads
192	    ? t('There are no Workloads with sidecar for this service')
193	    : `There are no Workloads with ${serverConfig.istioLabels.appLabelName || 'app'} and ${
194	        serverConfig.istioLabels.versionLabelName || 'version'
195	      } labels`;
196	
197	  const validWorkloads = getValidWorkloads();
198	  const validActions = hasMeshWorkloads && validWorkloads;
199	
200	  const dropdown = (
201	    <Dropdown
202	      data-test="service-actions-dropdown"
203	      id="actions"
204	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
205	        <MenuToggle
206	          ref={toggleRef}
207	          id="actions-toggle"
208	          onClick={() => onActionsToggle(!isActionsOpen)}
209	          data-test="service-actions-toggle"
210	          isExpanded={isActionsOpen}
211	          isDisabled={!validActions}
212	        >
213	          {t('Actions')}
214	        </MenuToggle>
215	      )}
216	      isOpen={isActionsOpen}
217	      onOpenChange={(isOpen: boolean) => onActionsToggle(isOpen)}
218	      onSelect={onActionsSelect}
219	      popperProps={{ placement: 'bottom-end' }}
220	    >
221	      <DropdownList>
222	        <ServiceWizardActionsDropdownGroup
223	          key="service_wizard_actions_dropdown_group"
224	          isDisabled={isDeleting || props.readOnly}
225	          virtualServices={props.virtualServices}
226	          destinationRules={props.destinationRules}
227	          k8sHTTPRoutes={props.k8sHTTPRoutes ?? []}
228	          k8sGRPCRoutes={props.k8sGRPCRoutes ?? []}
229	          annotations={props.annotations}
230	          istioPermissions={props.istioPermissions}
231	          onAction={onAction}
232	          onDelete={onAction}
233	        />
234	      </DropdownList>
235	    </Dropdown>
236	  );
237	  return (
238	    <>
239	      {!hasMeshWorkloads
240	        ? renderDisabledDropdownOption('tooltip_wizard_actions', TooltipPosition.top, toolTipMsgActions, dropdown)
241	        : dropdown}
242	
243	      <WizardLabels
244	        showAnotationsWizard={showAnnotationsWizard}
245	        type={'annotations'}
246	        onChange={annotations => onChangeAnnotations(annotations)}
247	        onClose={() => setShowAnnotationsWizard(false)}
248	        labels={props.annotations}
249	        canEdit={serverConfig.kialiFeatureFlags.istioAnnotationAction && !serverConfig.deployment.viewOnlyMode}
250	      />
251	
252	      <ServiceWizard
